      final dbHelper = DatabaseHelper();

      if (_isEditing) {
        final id = widget.existingData!['id'];
        await dbHelper.updateEntityLocal(
          'enquete_polygone',
          id,
          {
            'nom': _nomController.text.isEmpty ? null : _nomController.text,
            'points_json': jsonEncode(_closedCoordinates),
            'superficie_en_ha': _superficieHa,
            'code_gps': _codeGpsController.text.isEmpty
                ? null
                : _codeGpsController.text,
            'date_modification': now.toIso8601String(),
            'code_piste': _nearestPisteCode,
            'synced': 0,
          },
          recordHistory: true,
        );
      } else {
        await dbHelper.insertEntityLocal('enquete_polygone', {
          'nom': _nomController.text.isEmpty ? null : _nomController.text,
          'points_json': jsonEncode(_closedCoordinates),
          'superficie_en_ha': _superficieHa,
          'enqueteur': widget.agentName,
          'date_creation': now.toIso8601String(),
          'date_modification': null,
          'code_piste': _nearestPisteCode,
          'code_gps': _codeGpsController.text.isEmpty
              ? null
              : _codeGpsController.text,
          'synced': 0,
          'downloaded': 0,
          'login_id':
              ApiService.userId ?? await DatabaseHelper().resolveLoginId(),
          'saved_by_user_id': ApiService.userId,
          'commune_id': null,
        }, recordHistory: true);
      }

      if (mounted) {
        await showDialog(
          context: context,
          barrierDismissible: false,
          builder: (ctx) => AlertDialog(
            title: const Row(
              children: [
                Icon(Icons.check_circle, color: Colors.green),
                SizedBox(width: 8),
                Text('Succ\u00E8s'),
              ],
            ),
            content: Text(
              'Zone de Plaine "${_nomController.text.isNotEmpty ? _nomController.text : "Sans nom"}" enregistr\u00E9e\n'
              'Code Piste: ${_nearestPisteCode ?? "Non sp\u00E9cifi\u00E9"}\n'
              'Superficie: ${_superficieHa.toStringAsFixed(4)} ha\n'
              'Nombre de points: ${widget.polygonPoints.length}',
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.of(ctx).pop(),
                child: const Text('OK'),
              ),
            ],
          ),
        );
        if (mounted) {
          await clearDraftAfterSave();
          Navigator.of(context).pop(true);
        }
      }
    } catch (e) {
      print('Erreur sauvegarde polygone: $e');
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Erreur: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    } finally {
      if (mounted) setState(() => _isSaving = false);
    }
  }

  void _clearForm() {
    if (_isRegardEp) {
      final now = DateTime.now();
      _regardEpUuid = const Uuid().v4();
      setState(() {
        _regardEpCommuneName = '';
        _regardEpProvinceName = '';
        for (final field in _regardEpControllers.keys) {
          _regardEpControllers[field]!.text =
              _resolveRegardEpInitialValue(field, now);
        }
      });
      _populateRegardEpSpatialContext().then((_) {
        _applyRegardEpDerivedValues(now);
        if (mounted) {
          setState(() {});
        }
      });
      return;
    }

    setState(() {
      _nomController.clear();
    });
  }

