  Widget _buildRegardEpStaticField(
    String label,
    String value, {
    String? helperText,
  }) {
    final displayValue = value.trim().isEmpty ? 'Non d\u00E9termin\u00E9' : value.trim();
    return Container(
      margin: const EdgeInsets.only(bottom: 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            label,
            style: const TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Color(0xFF374151),
            ),
          ),
          const SizedBox(height: 8),
          Container(
            width: double.infinity,
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 16),
            decoration: BoxDecoration(
              color: const Color(0xFFF5F5F5),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: const Color(0xFFE0E0E0)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  displayValue,
                  style: const TextStyle(
                    fontSize: 14,
                    color: Color(0xFF374151),
                  ),
                ),
                if (helperText != null && helperText.trim().isNotEmpty) ...[
                  const SizedBox(height: 4),
                  Text(
                    helperText.trim(),
                    style: const TextStyle(
                      fontSize: 12,
                      color: Color(0xFF6B7280),
                    ),
                  ),
                ],
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildRegardEpGeometrySummaryField() {
    return Column(
      children: [
        _buildPolygonGpsInfo(),
        Container(
          margin: const EdgeInsets.only(bottom: 16),
          decoration: BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: const Color(0xFFE3F2FD)),
          ),
          padding: const EdgeInsets.all(16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Row(
                children: [
                  Icon(Icons.route, size: 20, color: Color(0xFF1976D2)),
                  SizedBox(width: 8),
                  Text(
                    'Coordonn\u00E9es des sommets',
                    style: TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                      color: Color(0xFF1976D2),
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 12),
              for (int i = 0; i < widget.polygonPoints.length; i++)
                _buildGpsInfoRow(
                  'Sommet ${i + 1}:',
                  '${widget.polygonPoints[i].latitude.toStringAsFixed(7)}, ${widget.polygonPoints[i].longitude.toStringAsFixed(7)}',
