  Widget _buildRegardEpField(String field) {
    final controller = _regardEpControllers[field];
    if (controller == null) return const SizedBox.shrink();

    final label = SrmConfig.getFieldLabel(widget.metier!, widget.entityType!, field);
    final options = _regardEpOptions[field] ?? const <Map<String, dynamic>>[];
    final isReadOnly = _isRegardEpReadOnlyField(field);
    final rule = SrmConfig.getFieldRule(widget.metier!, widget.entityType!, field);

    if (_isRegardEpBooleanField(field)) {
      final boolValue = controller.text.trim() == '1';
      return Container(
        margin: const EdgeInsets.only(bottom: 16),
        decoration: BoxDecoration(
          color: Colors.white,
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: const Color(0xFFE5E7EB)),
        ),
        child: SwitchListTile(
          title: Text(
            label,
            style: const TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Color(0xFF374151),
            ),
          ),
          value: boolValue,
          onChanged: isReadOnly
              ? null
              : (value) {
                  setState(() {
                    controller.text = value ? '1' : '0';
                    if (field == 'ep_anomalie' && !value) {
                      _regardEpControllers['anomalie_tamp']?.clear();
                      _regardEpControllers['anomalie_regard']?.clear();
                    }
                  });
                  onFieldChanged();
                },
          contentPadding: const EdgeInsets.symmetric(horizontal: 12),
        ),
      );
    }

    if (options.isNotEmpty) {
      if (isReadOnly) {
        return Container(
          margin: const EdgeInsets.only(bottom: 16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                label,
                style: const TextStyle(
                  fontSize: 14,
                  fontWeight: FontWeight.w600,
                  color: Color(0xFF374151),
                ),
              ),
              const SizedBox(height: 8),
              Container(
                width: double.infinity,
                padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 16),
                decoration: BoxDecoration(
                  color: const Color(0xFFF5F5F5),
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(color: const Color(0xFFE0E0E0)),
                ),
                child: Text(
                  _resolveRegardEpOptionLabel(field, controller.text.trim()),
                  style: const TextStyle(
                    fontSize: 14,
                    color: Color(0xFF374151),
                  ),
                ),
              ),
            ],
          ),
        );
      }

      final currentValue = controller.text.trim();
      final hasCurrentValue = currentValue.isNotEmpty &&
          options.any((option) => (option['code_value'] ?? '').toString() == currentValue);

      return Container(
        margin: const EdgeInsets.only(bottom: 16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              label,
              style: const TextStyle(
                fontSize: 14,
                fontWeight: FontWeight.w600,
                color: Color(0xFF374151),
              ),
            ),
            const SizedBox(height: 8),
            DropdownButtonFormField<String>(
              value: hasCurrentValue ? currentValue : null,
              decoration: InputDecoration(
                filled: true,
                fillColor: const Color(0xFFF9FAFB),
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(8),
                  borderSide: const BorderSide(color: Color(0xFFE5E7EB)),
                ),
                enabledBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(8),
                  borderSide: const BorderSide(color: Color(0xFFE5E7EB)),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(8),
                  borderSide: const BorderSide(color: Color(0xFF1976D2)),
                ),
              ),
              items: options
                  .map(
                    (option) => DropdownMenuItem<String>(
                      value: (option['code_value'] ?? '').toString(),
                      child: Text((option['label_value'] ?? '').toString()),
                    ),
                  )
                  .toList(),
              onChanged: (value) {
                controller.text = value ?? '';
                onFieldChanged();
              },
            ),
          ],
        ),
      );
    }

    if (isReadOnly) {
      return _buildRegardEpStaticField(
        label,
        _formatRegardEpDisplayValue(field, controller.text),
      );
    }

    return Container(
      margin: const EdgeInsets.only(bottom: 16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            label,
            style: const TextStyle(
              fontSize: 14,
              fontWeight: FontWeight.w600,
              color: Color(0xFF374151),
            ),
          ),
          const SizedBox(height: 8),
          TextFormField(
            controller: controller,
            enabled: !isReadOnly,
            readOnly: isReadOnly,
            keyboardType: _keyboardTypeForRegardEpRule(rule),
            inputFormatters: _inputFormattersForRegardEpRule(rule),
            maxLength: rule.maxLength,
            maxLines: rule.multiline ? 3 : 1,
            decoration: InputDecoration(
              hintText: _hintForRegardEpField(field),
              hintStyle: const TextStyle(color: Color(0xFF9CA3AF)),
              filled: true,
              fillColor: isReadOnly
                  ? const Color(0xFFF5F5F5)
                  : const Color(0xFFF9FAFB),
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(8),
                borderSide: const BorderSide(color: Color(0xFFE5E7EB)),
              ),
              enabledBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(8),
                borderSide: const BorderSide(color: Color(0xFFE5E7EB)),
              ),
              disabledBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(8),
                borderSide: const BorderSide(color: Color(0xFFE0E0E0)),
              ),
              focusedBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(8),
                borderSide: const BorderSide(color: Color(0xFF1976D2)),
              ),
            ),
          ),
        ],
      ),
    );
  }

  TextInputType _keyboardTypeForRegardEpRule(SrmFieldRule rule) {
    switch (rule.kind) {
      case SrmFieldKind.integer:
        return TextInputType.number;
      case SrmFieldKind.decimal:
        return const TextInputType.numberWithOptions(decimal: true, signed: true);
      case SrmFieldKind.date:
        return TextInputType.datetime;
      default:
        return TextInputType.text;
    }
  }

  List<TextInputFormatter> _inputFormattersForRegardEpRule(SrmFieldRule rule) {
    switch (rule.kind) {
      case SrmFieldKind.integer:
        return [FilteringTextInputFormatter.allow(RegExp(r'[0-9]'))];
      case SrmFieldKind.decimal:
        return [FilteringTextInputFormatter.allow(RegExp(r'[0-9,.\-]'))];
      case SrmFieldKind.date:
        return [FilteringTextInputFormatter.allow(RegExp(r'[0-9T:\-+.Z]'))];
      default:
        return const [];
    }
  }

  String _hintForRegardEpField(String field) {
    switch (field) {
      case 'z_radier':
      case 'z_surf':
        return 'Valeur libre';
      case 'ep_profondeur':
      case 'GENRATRICE_SUP':
      case 'ep_coor_z':
        return '0.000';
      case 'id_commune':
      case 'id_province':
      case 'id_user_creat':
      case 'id_user_modif':
      case 'id_user_valid':
        return 'Identifiant numerique';
      case 'date_creation':
      case 'date_modif':
      case 'date_validation':
        return 'YYYY-MM-DDTHH:MM:SS';
      case 'ep_date_insertion':
        return 'YYYY-MM-DD';
      default:
        return '';
    }
  }

